22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	const CURSED_SURCHARGE = 0.5;
25	
26	const ITEM_BASE_PREMIUM: Record<string, number> = {
27	  sword: 100,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	const COMPONENT_BLOCK_SIZE = 3;
34	const COMPONENT_BLOCK_PREMIUM = 60;
35	
36	const groupCountsByType = (items: Item[]): Map<string, number> => {
37	  const counts = new Map<string, number>();
38	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  return counts;
40	};
41	
42	const basePremiumForGroup = (type: string, count: number): number => {
43	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
44	  return count * ITEM_BASE_PREMIUM[type];
45	};
46	
47	const sumBasePremium = (counts: Map<string, number>): number => {
48	  let total = 0;
49	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
50	  return total;
51	};
52	
53	const itemSurcharges = (items: Item[]): number => {
54	  let total = 0;
55	  for (const item of items) {
56	    if (item.cursed) total += ITEM_BASE_PREMIUM[item.type] * CURSED_SURCHARGE;
57	  }
58	  return total;
59	};
60	
61	const calculatePremium = (items: Item[]): number => {
62	  const base = sumBasePremium(groupCountsByType(items));
63	  const surcharges = itemSurcharges(items);
64	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
65	  return Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE);
66	};
67	
68	export const runScenario = (scenario: Scenario): ScenarioResult => {
69	  const results = scenario.steps.map((step) => ({
70	    premium: calculatePremium(step.items ?? []),
71	  }));
72	  return { results };
73	};
